import sys
from typing import List

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def kthSmallestLargest(self, root: TreeNode, k: int) -> List[int]:
        def inorder_traversal(node):
            if node:
                yield from inorder_traversal(node.left)
                yield node.val
                yield from inorder_traversal(node.right)

        traversal = list(inorder_traversal(root))
        return [traversal[k-1], traversal[-k]]

if __name__ == '__main__':
    it = iter(sys.stdin.read().splitlines())
    try:
        n = int(next(it))
        root = None
        for _ in range(n):
            val = int(next(it))
            if not root:
                root = TreeNode(val)
            else:
                node = root
                while True:
                    if val < node.val:
                        if node.left:
                            node = node.left
                        else:
                            node.left = TreeNode(val)
                            break
                    else:
                        if node.right:
                            node = node.right
                        else:
                            node.right = TreeNode(val)
                            break
        k = int(next(it))
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.kthSmallestLargest(root, k)
    print(ans[0])
    print(ans[1])

