#include <numeric>
#include <iostream>
#include <vector>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    vector<int> kthSmallestLargest(TreeNode* root, int k) {
        vector<int> result;
        inorder_traversal(root, result);
        return {result[k-1], result[result.size()-k]};
    }
private:
    void inorder_traversal(TreeNode* node, vector<int>& result) {
        if (node) {
            inorder_traversal(node->left, result);
            result.push_back(node->val);
            inorder_traversal(node->right, result);
        }
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    TreeNode* root = nullptr;
    for (int i = 0; i < n; i++) {
        int val;
        cin >> val;
        if (!root) {
            root = new TreeNode(val);
        } else {
            TreeNode* node = root;
            while (true) {
                if (val < node->val) {
                    if (node->left) {
                        node = node->left;
                    } else {
                        node->left = new TreeNode(val);
                        break;
                    }
                } else {
                    if (node->right) {
                        node = node->right;
                    } else {
                        node->right = new TreeNode(val);
                        break;
                    }
                }
            }
        }
    }
    int k;
    cin >> k;
    Solution sol;
    vector<int> ans = sol.kthSmallestLargest(root, k);
    cout << ans[0] << endl;
    cout << ans[1] << endl;
    return 0;
}
